import { genSVGCubicBezier } from '@/utils/helper';
import type { Component } from 'solid-js';
import { IconProps } from '../toast.type';

export const Warning: Component<IconProps> = (props: IconProps) => {
  const fill = props.primary || 'var(--color-warning)';
  const stroke = props.secondary || '#000';
  return (
    <svg style={{ overflow: 'visible' }} viewBox="0 0 32 32" width="1.25rem" height="1.25rem">
      <g>
        {/* Equilateral triangle with rounded corners */}
        <path
          fill={fill}
          stroke={fill}
          stroke-width="10"
          stroke-linejoin="round"
          stroke-linecap="round"
          d="M16 1 L31 27 L1 27 Z"
          opacity="0"
        >
          <animate
            attributeName="opacity"
            values="0;1"
            dur="0.3s"
            begin="0ms"
            fill="freeze"
            {...genSVGCubicBezier('0.0, 0.0, 0.58, 1.0')}
          />
          <animateTransform
            attributeName="transform"
            type="scale"
            values="0.5;1.1;1"
            dur="0.4s"
            begin="0ms"
            fill="freeze"
            keyTimes="0;0.7;1"
            keySplines="0.25 0.71 0.4 0.88; .59 .22 .87 .63"
            calcMode="spline"
          />
        </path>
        {/* Exclamation line - shorter and centered */}
        <path
          fill="none"
          stroke={stroke}
          stroke-width="2.5"
          stroke-dasharray="6"
          stroke-dashoffset="6"
          stroke-linecap="round"
          d="M16,11 L16,17"
        >
          <animate
            attributeName="stroke-dashoffset"
            values="6;0"
            dur="0.2s"
            begin="300ms"
            fill="freeze"
            {...genSVGCubicBezier('0.0, 0.0, 0.58, 1.0')}
          />
        </path>
        {/* Exclamation dot - smaller and higher */}
        <circle fill={stroke} cx="16" cy="21.5" r="0">
          <animate
            attributeName="r"
            values="0;1.8;1.5"
            dur="0.25s"
            begin="400ms"
            fill="freeze"
            keyTimes="0;0.6;1"
            keySplines="0.25 0.71 0.4 0.88; .59 .22 .87 .63"
            calcMode="spline"
          />
        </circle>
        {/* Bell shake animation - continuous */}
        <animateTransform
          attributeName="transform"
          type="rotate"
          values="0 16 27; -8 16 27; 8 16 27; -5 16 27; 5 16 27; -2 16 27; 2 16 27; 0 16 27"
          dur="0.6s"
          begin="500ms;shake.end+2s"
          fill="freeze"
          id="shake"
        />
      </g>
    </svg>
  );
};
